import React from "react"
import './SignIn.css';
import { useState } from 'react';



export function SignIn(){
    const [login, setLogin] = useState('')

    const [pass, setPass] = useState('')

    const changePass = (event) =>{
        setPass(event.target.value)
    }

    const changeLogin = (event) =>{
        setLogin(event.target.value)
    }

    return(
        <div className="signinСontainer">
            <header className="signinСontainerHeader"> </header>
            <div className="parent-container">
                <div className="formsign">
                   <div className="titleform">
                    Не узнаем ваши лапки <br/>
                    Авторизируйтесь
                   </div>
                   <div className="input-group">
                      <input type="text" className="input-field" placeholder="Логин или Email" value={login} onChange={changeLogin}/>
                      <input type="text" className="input-field" placeholder="Пароль" value={pass} onChange={changePass}/>
                      <button class="button-style">Войти</button>
                      
                   </div>
                </div>
            </div>
        </div>
    )
}
